"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[868729],{50025:s=>{s.exports=JSON.parse('{"tag":{"label":"skins","permalink":"/dst-api-webdocs/docs/tags/skins","allTagsPath":"/dst-api-webdocs/docs/tags","count":13,"items":[{"id":"game-scripts/beefalo_clothing","title":"Beefalo Clothing","description":"Defines skin customization data tables for beefalo appearance parts including body, feet, head, horn, and tail variants.","permalink":"/dst-api-webdocs/docs/game-scripts/beefalo_clothing"},{"id":"game-scripts/prefabs/beefalo_groomer","title":"Beefalo Groomer","description":"A structure prefab that allows players to groom and dress beefalos with custom skins and clothing.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/beefalo_groomer"},{"id":"game-scripts/clothing","title":"Clothing","description":"This auto-generated file defines static configuration data for clothing items, including skin attributes, symbol overrides, and sound effects used by the account items system.","permalink":"/dst-api-webdocs/docs/game-scripts/clothing"},{"id":"game-scripts/widgets/redux/craftingmenu_skinselector","title":"Craftingmenu Skinselector","description":"Manages skin selection UI for crafting recipes, displaying available skins and syncing selection with the crafting menu.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/redux/craftingmenu_skinselector"},{"id":"game-scripts/item_blacklist","title":"Item Blacklist","description":"A static data module defining tables for item display blacklisting, skin decoration visibility, event locks, and unlockable skins.","permalink":"/dst-api-webdocs/docs/game-scripts/item_blacklist"},{"id":"game-scripts/prefabskin","title":"Prefabskin","description":"This component defines initialization and cleanup functions for applying and removing skins on various prefabs including structures, items, weapons, armor, hats, and pets, managing animation overrides, visual effects, sound effects, component states, and event listeners, with a factory function to register skin prefabs.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabskin"},{"id":"game-scripts/prefabskins","title":"Prefabskins","description":"This module defines the PREFAB_SKINS table mapping prefabs to skin identifiers, along with a selection blacklist and a reverse lookup table for skin IDs.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabskins"},{"id":"game-scripts/screens/redux/scarecrowpopupgridloadout","title":"Scarecrowpopupgridloadout","description":"Manages the UI popup for selecting and applying clothing skins to a scarecrow character in the wardrobe interface.","permalink":"/dst-api-webdocs/docs/game-scripts/screens/redux/scarecrowpopupgridloadout"},{"id":"game-scripts/skin_gifts","title":"Skin Gifts","description":"A data configuration file mapping skin item names to gift types and defining popup display data for each gift category.","permalink":"/dst-api-webdocs/docs/game-scripts/skin_gifts"},{"id":"game-scripts/prefabs/skinprefabs","title":"Skinprefabs","description":"This module registers cosmetic skin prefabs for characters, items, structures, and tools using CreatePrefabSkin, defining initialization callbacks, rarity levels, and skin-specific behavior including bloom effects and color changes.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/skinprefabs"},{"id":"game-scripts/screens/redux/skinpresetspopup","title":"SkinPresetsPopup","description":"Displays a scrolling list of skin presets for a specific character, allowing users to load or save custom skin configurations.","permalink":"/dst-api-webdocs/docs/game-scripts/screens/redux/skinpresetspopup"},{"id":"game-scripts/skinsfiltersutils","title":"Skinsfiltersutils","description":"Provides filtering utilities for selecting subsets of skins based on type, rarity, item ID, and colour.","permalink":"/dst-api-webdocs/docs/game-scripts/skinsfiltersutils"},{"id":"game-scripts/screens/redux/wardrobepopupgridloadout","title":"Wardrobepopupgridloadout","description":"Manages the UI screen for selecting and applying character skins via a grid-style loadout interface in DST\'s Redux UI system.","permalink":"/dst-api-webdocs/docs/game-scripts/screens/redux/wardrobepopupgridloadout"}],"unlisted":false}}')}}]);